public static long[][] solve(long[][] grid, long x, long y, long k) {
    // Create a copy of the grid to avoid modifying the original
    long[][] result = new long[grid.length][grid[0].length];
    for (int i = 0; i < grid.length; i++) {
        for (int j = 0; j < grid[0].length; j++) {
            result[i][j] = grid[i][j];
        }
    }

    // Extract the submatrix
    long[][] submatrix = new long[k][k];
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < k; j++) {
            submatrix[i][j] = result[(int)x + i][(int)y + j];
        }
    }

    // Reverse the submatrix
    for (int i = 0; i < k / 2; i++) {
        long[] temp = submatrix[i];
        submatrix[i] = submatrix[k - 1 - i];
        submatrix[k - 1 - i] = temp;
    }

    // Put the reversed submatrix back into the result
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < k; j++) {
            result[(int)x + i][(int)y + j] = submatrix[i][j];
        }
    }

    return result;
}
